  "plan": {
    "problem": "Persistent input_errors on router1 and router2 Gi0/0/1 (receive-side physical-layer faults causing frame errors on the link).",
    "fix_summary": "Clear counters to establish a clean baseline, replace the patch cable, and replace the local transceiver on each affected interface. Validate by observing counters after changes.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router1",
        "action": "clear_interface_counters",
        "target": "GigabitEthernet0/0/1",
